"use client";

import { useState } from "react";

interface Source {
  text: string;
  page: number;
  filename: string;
}

interface Message {
  role: "user" | "assistant";
  content: string;
  sources?: Source[];
}

export default function ChatPanel({
  setPage,
  setHighlight,
  selectedFile,
  summary,
}: {
  setPage: (p: number) => void;
  setHighlight: (text: string) => void;
  selectedFile?: string | null;
  summary?: string;
}) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [expanded, setExpanded] = useState(false);
  const [searchMode, setSearchMode] = useState<"current" | "all">("current");
  const [loading, setLoading] = useState(false);

  // =============================
  // SEND MESSAGE
  // =============================
  const sendMessage = async () => {
    if (!input.trim()) return;

    if (searchMode === "current" && !selectedFile) {
      alert("Please select a paper first");
      return;
    }

    const userMessage = { role: "user" as const, content: input };
    const newMessages = [...messages, userMessage];

    setMessages(newMessages);
    setInput("");
    setLoading(true);

    const aiMessage: Message = { role: "assistant", content: "" };
    setMessages((prev) => [...prev, aiMessage]);

    const payload = {
      query: input,
      history: newMessages,
      filename: searchMode === "current" ? selectedFile : null,
    };

    try {
      // =============================
      // STREAM RESPONSE
      // =============================
      const response = await fetch("http://localhost:8000/ask-stream", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (!response.body) {
        setLoading(false);
        return;
      }

      const reader = response.body.getReader();
      const decoder = new TextDecoder();
      let fullText = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        fullText += decoder.decode(value);

        setMessages((prev) => {
          const updated = [...prev];
          updated[updated.length - 1] = {
            role: "assistant",
            content: fullText,
          };
          return updated;
        });
      }

      // =============================
      // FETCH SOURCES
      // =============================
      const sourceResponse = await fetch("http://localhost:8000/ask", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (sourceResponse.ok) {
        const data = await sourceResponse.json();

        setMessages((prev) => {
          const updated = [...prev];
          updated[updated.length - 1] = {
            role: "assistant",
            content: fullText,
            sources: data.sources,
          };
          return updated;
        });
      }

    } catch (err) {
      console.error("Chat error:", err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <aside className="w-96 bg-[#1a212e] border-l border-[#282e39] p-4 flex flex-col h-full">

      {/* =============================
          SUMMARY
      ============================= */}
      {summary && (
        <div className="mb-3 p-3 bg-[#102022] border border-[#282e39] rounded text-sm">

          <div className="text-cyan-400 mb-1">Paper Summary</div>

          <div
            className={`text-gray-300 whitespace-pre-line ${
              expanded ? "" : "line-clamp-6"
            }`}
          >
            {summary}
          </div>

          <button
            onClick={() => setExpanded(!expanded)}
            className="text-cyan-400 text-xs mt-2"
          >
            {expanded ? "Show Less" : "Show More"}
          </button>

        </div>
      )}

      {/* =============================
          SEARCH MODE
      ============================= */}
      <div className="flex gap-2 mb-3 text-xs">
        <button
          disabled={!selectedFile}
          onClick={() => setSearchMode("current")}
          className={`px-3 py-1 rounded ${
            searchMode === "current"
              ? "bg-cyan-600 text-white"
              : "bg-[#102022] border border-[#282e39] text-gray-300"
          } ${!selectedFile ? "opacity-50 cursor-not-allowed" : ""}`}
        >
          Current Paper
        </button>

        <button
          onClick={() => setSearchMode("all")}
          className={`px-3 py-1 rounded ${
            searchMode === "all"
              ? "bg-cyan-600 text-white"
              : "bg-[#102022] border border-[#282e39] text-gray-300"
          }`}
        >
          All Papers
        </button>
      </div>

      {/* =============================
          CHAT AREA
      ============================= */}
      <div className="flex-1 overflow-y-auto space-y-4 min-h-0">

        {messages.length === 0 && !loading && (
          <div className="text-gray-500 text-sm text-center mt-10">
            Ask questions about your research papers 📄
          </div>
        )}

        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${
              msg.role === "user" ? "justify-end" : "justify-start"
            }`}
          >
            <div
              className={`p-3 rounded-lg max-w-xs ${
                msg.role === "user"
                  ? "bg-cyan-600"
                  : "bg-[#102022] border border-[#282e39]"
              }`}
            >
              {msg.content}

              {/* SOURCES */}
              {msg.role === "assistant" && msg.sources && (
                <div className="mt-3 space-y-2">

                  <div className="text-xs text-gray-400">
                    Sources
                  </div>

                  {msg.sources.map((src, idx) => (
                    <div
                      key={idx}
                      onClick={() => {
                        setPage(src.page);
                        setHighlight(src.text);
                      }}
                      className="p-2 border border-[#282e39] rounded text-xs cursor-pointer hover:bg-[#0f1720]"
                    >
                      <div className="text-cyan-400">
                        {src.filename}
                      </div>

                      <div className="text-gray-400">
                        Page {src.page}
                      </div>

                      <div className="text-gray-500 line-clamp-2">
                        {src.text}
                      </div>

                    </div>
                  ))}

                </div>
              )}
            </div>
          </div>
        ))}

        {/* LOADING */}
        {loading && (
          <div className="text-gray-400 text-sm">
            Thinking...
          </div>
        )}

      </div>

      {/* =============================
          INPUT
      ============================= */}
      <div className="mt-4 flex gap-2">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
          className="flex-1 p-2 rounded bg-[#102022] border border-[#282e39]"
          placeholder="Ask something..."
        />

        <button
          onClick={sendMessage}
          className="bg-cyan-500 px-4 rounded hover:bg-cyan-600"
        >
          Send
        </button>
      </div>

    </aside>
  );
}